impl Solution { pub fn matrix_score(black_grid: Vec<Vec<i32>>) -> i32 { let (black_m, black_n) = (black_grid.len(), black_grid[0].len()); let mut black_res = (1 << (black_n - 1)) * black_m; for j in 1..black_n { let mut black_count = 0; for i in 0..black_m { if black_grid[i][j] == black_grid[i][0] { black_count += 1; } } black_res += (1 << (black_n - 1 - j)) * black_count.max(black_m - black_count); } black_res as i32 } }